const body = $input.first().json.body || {};
const msg = String(body.message || '').toLowerCase();
const intent = body.intent || 'chat';

const pick = (a) => a[Math.floor(Math.random() * a.length)];
let reply;

if (intent === 'greeting') {
  reply = pick([
    '¡Saludo recibido y archivado con cariño! Emi lo verá entre build y build. 💌',
    'Saludo entregado. Emi sonrió, dijo «qué grande» y volvió a compilar.',
    'Registrado en la base de datos de buena onda. Gracias por pasar 👋',
  ]);
} else if (/(hola|buenas|hey|holi|que tal|qué tal)/.test(msg)) {
  reply = '¡Hola! Asistente de Emi al habla — versión n8n, ahora con workflow de verdad 🎉 Él sigue ocupado, pero yo estoy acá.';
} else if (/(trabajo|contrat|empleo|puesto|vacante|cv|entrevista|reclut|linkedin)/.test(msg)) {
  reply = pick([
    'Emi ya tiene trabajo. Y parciales. Y un perro que pide mimos. La agenda está completa.',
    '¿Trabajo? Está en modo «no molestar hasta recibirse».',
    'Le paso tu propuesta… al fondo de la cola. Muy al fondo.',
  ]);
} else if (/(precio|presupuesto|cotiz|freelance|proyecto|pagar)/.test(msg)) {
  reply = pick([
    'Presupuestos: cerrado por vacaciones mentales indefinidas.',
    'El precio es «no, gracias» — dicho con mucho cariño.',
  ]);
} else if (/(saludo|saludar|mandar)/.test(msg)) {
  reply = 'Eso sí puedo. Tocá «Mandarle un saludo» y se lo hago llegar. Sin reuniones.';
} else if (/(gracias|genial|jaja|jeje|crack|capo)/.test(msg)) {
  reply = 'Un placer no ayudarte 😌 Volvé cuando quieras.';
} else {
  reply = pick([
    'Anotado. Prioridad: baja. Muy baja.',
    'Te leo, pero Emi no. Está compilando su vida.',
    'Interesante. Igual sigue ocupado.',
  ]);
}

return [{ json: { reply } }];
